import org.springframework.security.crypto.bcrypt.BCryptPasswordEncoder; public class BcryptTest { public static void main(String[] args) { BCryptPasswordEncoder encoder = new BCryptPasswordEncoder(); System.out.println("Matches: " + encoder.matches("admin123", "$2a$10$N.ZOn9MHSbEU0Oq6lZXaF.kXBqb0h.VDd7jqDeYRcP1XlVLYN9Cku")); System.out.println("Correct Hash: " + encoder.encode("admin123")); } }
